const raw = $input.first().json;
const event = raw.body ?? raw;
const d = event.d ?? event;

if (event.t !== 'MESSAGE_CREATE' && event.type !== 0) return [];
if (String(d.channel_id) !== String($env.TL_CHANNEL_ID)) return [];
if (d.author?.bot || d.webhook_id) return [];
const content = String(d.content || '').trim();
if (!content) return [];

return [{ json: {
  content,
  author_id: d.author?.id,
  channel_id: d.channel_id,
  message_id: d.id
} }];

// C-01: Only the Team Lead (role=team_lead) may interact with this workflow
const authorId = String($('Filter Message').first().json.author_id);
const rosterRows = $('Fetch Roster').all();
const tl = rosterRows.find(r => r.json.role === 'team_lead');

if (!tl || String(tl.json.discord_id) !== authorId) {
  return [{ json: { tlVerified: false } }];
}
return [{ json: { tlVerified: true } }];

const j = $input.first().json;
if (!((j.tlVerified) === true)) return [];
return $input.all();

const msg_ctx = $('Filter Message').first().json;
const rosterRows = $('Fetch Roster').all();
const msg = msg_ctx.content.trim();

// C-02/M-03: normalize + word-boundary (consistent with F-08)
const normalize = s => String(s).normalize('NFKD').replace(/[^\x00-\x7F]/g, '').toLowerCase();
const msgNorm = normalize(msg);

const hasWordBoundary = (haystack, needle) => {
  let idx = 0;
  while ((idx = haystack.indexOf(needle, idx)) !== -1) {
    const pre  = idx === 0 || !/[a-z0-9]/.test(haystack[idx - 1]);
    const post = idx + needle.length >= haystack.length || !/[a-z0-9]/.test(haystack[idx + needle.length]);
    if (pre && post) return true;
    idx++;
  }
  return false;
};

// Named individual detection (no length gate — handles short names)
let asksForNamed = false;
for (const row of rosterRows) {
  const name = normalize(row.json.name || '');
  if (!name.trim()) continue;
  const parts = name.split(/\s+/).filter(p => p.length > 0);
  for (const part of parts) {
    if (hasWordBoundary(msgNorm, part)) {
      asksForNamed = true;
      break;
    }
  }
  if (asksForNamed) break;
}

// SC-13: explain what the agent does / what data it used — checked first so an
// explain question phrased as a question ('why did you...?') isn't misread as status_question.
const explainKeywords = ['explain', 'what do you do', 'what data', 'how do you work', 'why did you', 'quelles donnees', 'explique'];
const isExplainRequest = explainKeywords.some(kw => msgNorm.includes(kw));

const reportKeywords = ['report', 'rapport', 'generate', 'weekly', 'status report', 'genere'];
const isReportRequest = !isExplainRequest && reportKeywords.some(kw => msgNorm.includes(kw));

const questionIndicators =
  msg.endsWith('?') ||
  /\b(how|status|quel|comment|blocked|progress|blocker|update)\b/.test(msgNorm);
const isStatusQuestion = !isExplainRequest && !isReportRequest && questionIndicators;

let intent;
if (isExplainRequest) intent = 'explain_request';
else if (isReportRequest) intent = 'report_request';
else if (isStatusQuestion) intent = 'status_question';
else intent = 'unknown';

return [{ json: {
  intent,
  asksForNamed,
  content: msg_ctx.content,
  author_id: msg_ctx.author_id,
  channel_id: msg_ctx.channel_id,
  message_id: msg_ctx.message_id
} }];

// L-02: hard fail if variable not configured (avoids silent swallow)
if (!$env.F01_WORKFLOW_ID) {
  throw new Error('F01_WORKFLOW_ID n8n variable is not configured. Import the F-01 workflow first.');
}
return [{ json: {
  trigger: 'on_demand',
  requested_by: $('Classify Intent').first().json.author_id
} }];

